export type HelixStreamingTraceEvent =
  | {
    tag: "Pulse";
    start_us: bigint;
    duration_us: bigint;
    pulse_id: bigint;
    previous_consumed_mel_frames: bigint;
    consumed_mel_frames: bigint;
    pulse_mel_frames: bigint;
    committed_text_len_start: bigint;
    speculative_len_start: bigint;
    committed_tokens: bigint;
    retained_speculative_tokens: bigint;
    resident_committed_tokens: bigint;
    evicted_audio_tokens: bigint;
    evicted_committed_tokens: bigint;
  }
  | {
    tag: "AudioEncoderUpdate";
    start_us: bigint;
    duration_us: bigint;
    pulse_id: bigint;
    num_audio_frames: bigint;
    first_audio_token_id: bigint;
    resident_audio_frames: bigint;
    changed_span_count: bigint;
    changed_audio_tokens: bigint;
    latest_audio_representation_version: bigint;
  }
  | {
    tag: "AudioEviction";
    timestamp_us: bigint;
    pulse_id: bigint;
    evicted_audio_tokens: bigint;
    first_audio_token_id: bigint;
    resident_audio_frames: bigint;
    audio_ring_capacity: bigint;
  }
  | {
    tag: "RefreshPrompt";
    start_us: bigint;
    duration_us: bigint;
    pulse_id: bigint;
    first_audio_token_id: bigint;
    resident_audio_frames: bigint;
    committed_text_len: bigint;
    resident_committed_len: bigint;
    resident_text_len: bigint;
    logical_start: bigint;
    logical_end: bigint;
    text_token_start: bigint;
    text_token_end: bigint;
    spans: HelixTracePositionSpan[];
  }
  | {
    tag: "LayoutSnapshot";
    timestamp_us: bigint;
    pulse_id: bigint;
    audio_len: bigint;
    audio_head: bigint;
    first_audio_token_id: bigint;
    text_len: bigint;
    first_text_token_id: bigint;
    prompt_len: bigint;
    resident_committed_len: bigint;
    resident_text_len: bigint;
  }
  | {
    tag: "Verify";
    start_us: bigint;
    duration_us: bigint;
    pulse_id: bigint;
    rewind_k: bigint;
    post_rewind_text_len: bigint;
    text_token_start: bigint;
    text_token_end: bigint;
    logical_start: bigint;
    logical_end: bigint;
    spans: HelixTracePositionSpan[];
    accepted_prefix_len: bigint | null;
    divergence_row: bigint | null;
    next_token_seed: bigint | null;
    discarded_speculative_tokens: bigint | null;
    invalidated_speculative_slots: bigint | null;
  }
  | {
    tag: "ArDecode";
    start_us: bigint;
    duration_us: bigint;
    pulse_id: bigint;
    decode_steps: bigint;
    decoded_tokens: bigint;
    speculative_len_entering: bigint;
    live_speculative_tokens: bigint;
    hit_eos: boolean;
    seed_token_id: bigint;
    seed_token_text: string;
    early_exit_reason: HelixArDecodeEarlyExitReason;
    next_after_tail: bigint;
  }
  | {
    tag: "ArToken";
    start_us: bigint;
    duration_us: bigint;
    pulse_id: bigint;
    step_index: bigint;
    input_token_id: bigint;
    input_text: string;
    text_token_id: bigint;
    query_position: bigint;
    physical_start: bigint;
    summary_records: bigint;
    next_token_id: bigint;
    next_text: string;
  }
  | {
    tag: "Commit";
    start_us: bigint;
    duration_us: bigint;
    pulse_id: bigint;
    speculative_len_pre: bigint;
    revisable_tail_target: bigint;
    committed_tokens: bigint;
    retained_speculative_tokens: bigint;
    committed_text_len: bigint;
    next_after_committed: bigint;
  }
  | {
    tag: "VerifySkipped";
    timestamp_us: bigint;
    pulse_id: bigint;
    reason: HelixVerifySkippedReason;
    rewind_k: bigint;
    resident_committed_len: bigint;
    speculative_len: bigint;
  }
  | {
    tag: "TextEviction";
    timestamp_us: bigint;
    pulse_id: bigint;
    evicted_committed_tokens: bigint;
    resident_committed_capacity: bigint;
    committed_text_len: bigint;
  };

